#include <WiFi.h>
#include <HTTPClient.h>

// Configuration constants
#define WIFI_SSID "YourWiFiSSID"
#define WIFI_PASSWORD "YourWiFiPassword"
#define API_SECRET_KEY "YourAPISecretKey"
#define CLOUD_SERVICE_URL "http://api.yourcloudservice.com/upload"

// Function declarations
void connectToWiFi();
void uploadImageData(const char* imageData);

void setup() {
    Serial.begin(115200);
    connectToWiFi();
}

void loop() {
    // Placeholder for image capture logic
    const char* sampleImageData = "Sample Image Data";

    uploadImageData(sampleImageData);

    // Add a delay to match your upload frequency requirements
    delay(5000);
}

void connectToWiFi() {
    Serial.print("Connecting to WiFi");
    WiFi.begin(WIFI_SSID, WIFI_PASSWORD);

    while (WiFi.status() != WL_CONNECTED) {
        delay(1000);
        Serial.print(".");
    }
    Serial.println("\nConnected to WiFi");
}

void uploadImageData(const char* imageData) {
    if (WiFi.status() == WL_CONNECTED) {
        HTTPClient http;
        http.begin(CLOUD_SERVICE_URL);
        http.addHeader("Content-Type", "application/json");
        http.addHeader("Authorization", API_SECRET_KEY);
        
        // Create a JSON payload
        String payload = "{\"imageData\":\"" + String(imageData) + "\"}";
        
        int httpResponseCode = http.POST(payload);

        if (httpResponseCode > 0) {
            String response = http.getString();
            Serial.println("Response: " + response);
        } else {
            Serial.print("Error on sending POST: ");
            Serial.println(httpResponseCode);
        }
        http.end();
    } else {
        Serial.println("WiFi not connected");
    }
}